data.code:
margin: 0;
font-family: 'Quicksand', sans-serif;
background: #fff0f5;
color: #4a4a4a;
overflow-x: hidden;

display: flex;
justify-content: space-around;
align-items: center;
padding: 15px 30px;
background: #ff69b4;
box-shadow: 0 4px 15px rgba(255,105,180,0.4);
position: sticky;
top: 0;
z-index: 100;

color: #fff;
text-decoration: none;
font-weight: bold;
font-size: 1.1rem;
cursor: pointer;
transition: transform 0.2s, color 0.2s;

display: flex;
flex-direction: column;
align-items: center;
justify-content: center;
min-height: 80vh;
text-align: center;
padding: 40px;

font-size: 4rem;
color: #ff1493;
margin-bottom: 20px;
text-transform: uppercase;
letter-spacing: 2px;

display: grid;
grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
gap: 30px;
margin-top: 40px;

background: #fff;
border-radius: 20px;
padding: 20px;
box-shadow: 0 10px 30px rgba(255,105,180,0.15);
transition: transform 0.3s ease;
border: 2px solid #ffe4e1;

background: linear-gradient(45deg, #ff69b4, #ff1493);
color: #fff;
padding: 15px 40px;
border: none;
border-radius: 30px;
font-size: 1.2rem;
font-weight: bold;
cursor: pointer;
box-shadow: 0 5px 15px rgba(255,20,147,0.3);
transition: all 0.3s ease;

width: 100%;
height: 200px;
object-fit: cover;
border-radius: 10px;
margin-bottom: 15px;

display: flex;
gap: 30px;
align-items: center;
justify-content: center;

width: 100%;
max-width: 400px;
border-radius: 50%;
border: 8px solid #ffe4e1;
box-shadow: 0 10px 30px rgba(255,105,180,0.3);
margin-top: 30px;
object-fit: cover;
